import React from 'react';
import {StyleSheet, View, ImageBackground} from 'react-native';
import {useTranslation} from 'react-i18next';
import {useTheme} from '@react-navigation/native';
import Button from '../../component/Button';
import NavigationService from '../../navigation/NavigationService';
import {isArabic} from '../../locales';
import reactotron from 'reactotron-react-native';

export default function StaticFormsBtn(): JSX.Element {
  const {t} = useTranslation();
  const {colors}: any = useTheme();
  const style = getStyle(colors);

  return (
    <View style={style.container}>
      <Button
        style={style.btn}
        h2
        bold
        title={'طلب تسجيل مادة للإعفاء الجمركي'}
        styleText={{color: colors.mainWhite}}
        onPress={() => {
          NavigationService.navigate('IssuePricePreferenceCertificate');
        }}></Button>
      <Button
        style={style.btn}
        h2
        bold
        title={'طلب تسجيل مادة للإعفاء الجمركي'}
        styleText={{color: colors.mainWhite}}
        onPress={() => {
          NavigationService.navigate(
            'RequestRegistrationOfIndustrialInputForCustomsDutyExemption',
          );
        }}></Button>
      <Button
        style={style.btn}
        h2
        bold
        title={'اعفاء'}
        styleText={{color: colors.mainWhite}}
        onPress={() => {
          NavigationService.navigate('DutyExemption');
        }}></Button>
      <Button
        style={style.btn}
        h2
        bold
        title={
          isArabic()
            ? 'إصدار رخصة إنتاج صناعي'
            : 'Issue Industrial Production License'
        }
        styleText={{color: colors.mainWhite}}
        onPress={() => {
          NavigationService.navigate('IssueIndustrialProductionLicense', {
            service: {serviceId: '10'},
          });
        }}></Button>
      <Button
        style={style.btn}
        h2
        bold
        title={'تجديد رخصة إنتاج صناعي'}
        styleText={{color: colors.mainWhite}}
        onPress={() => {
          NavigationService.navigate('RenewalLicenseOptions', {
            service: {serviceId: '19'},
          });
        }}></Button>
      <Button
        style={style.btn}
        h2
        bold
        title={'تسجيل مادة للإعفاء الجمركي'}
        styleText={{color: colors.mainWhite}}
        onPress={() => {
          NavigationService.navigate(
            'RegistrationIndustrialCustomsDutyExemption',
          );
        }}></Button>
      <Button
        style={style.btn}
        h2
        bold
        title={'تعديل رخصة إنتاج صناعي'}
        styleText={{color: colors.mainWhite}}
        onPress={async () => {
          NavigationService.navigate('IssueIndustrialProductionLicense', {
            service: {serviceId: '21'},
          });
        }}></Button>
    </View>
  );
}
